function Home(props) {
    return (
      <div className="container">
        <div className="row">
          <div className="btn" onClick={() => props.navigation.go("ClientDetails")}>
            Enviar
          </div>
          <div className="btn" onClick={props.navigation.back}>
            Back
          </div>
        </div>
        <div className="row">
          <h1>Home</h1>
        </div>
      </div>
    );
  }
  
  export default Home;
